#include<bits/stdc++.h>
using namespace std;
long long n,x,y,a[1000010],s[1000010];
vector<long long> mp[1000010];
constexpr long long mod=1e9+7;
void dfs(long long x,long long fa=-1)
{
    a[x]=1;
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            s[x]+=((a[x]-1+mod)%mod)*((a[i]*2-1+mod)%mod)%mod;
            s[x]%=mod;
            a[x]+=(a[i]*2%mod-1+mod)%mod;
            a[x]%=mod;
        }
    }
}
void dfs1(long long x,long long val,long long fa=-1)
{
    val=(val%mod+mod)%mod;
    s[x]+=(a[x]*val%mod-1+mod)%mod;
    s[x]%=mod;
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs1(i,((val-1+(a[x]-a[i]*2+1))%mod+mod)%mod*2%mod,x);
        }
    }
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs(1);
    dfs1(1,1);
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        ans^=(1ll*i*((s[i]%mod+mod)%mod));
    }
    printf("%lld",ans);
    return 0;
}
